import math; from itertools import product; S0, K, H, r, sigma, T, n = 100, 90, 120, 0.05, 0.3, 0.5, 4; dt = T/n; u = math.exp(sigma*math.sqrt(dt)); d = 1/u; p = (math.exp(r*dt)-d)/(u-d); total = 0;
for moves in product(['U','D'], repeat=n):
    path = [S0];
    for m in moves:
        path.append(path[-1]*u if m=='U' else path[-1]*d)
    if not any(s >= H for s in path):
        payoff = max(path[-1]-K, 0)
        prob = (p**moves.count('U'))*((1-p)**moves.count('D'))
        total += prob*payoff
print(round(math.exp(-r*T)*total, 4))
